from typing import Set, List, Optional, Iterable, Mapping

import numpy as np
from geosat.cloud import PointCloud
from geosat.psanp.abstractions.classifier import Classifier
from geosat.psanp.abstractions.option import Option
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata

from psanp.classifiers.tensorflow.point_net_classifiers.post_process import (
    densify_vegetation,
    clean_rail,
    osm_building_classification,
    ProjectTypeEnum,
    classify_vertical_near_rail,
    classify_catenary_post,
    classify_cable,
    classify_rail_mask,
)


class AtoPostProcessingClassifier(Classifier):
    def __init__(
        self,
        projection: Optional[ProjectTypeEnum] = None,
        stage_name: Optional[str] = None,
    ):
        super().__init__(stage_name)
        self.projection = projection

    def input_classes(self) -> Set[str]:
        return {"unclassified", "ground", "vegetation", "catenary", "rail", "building"}

    def output_classes(self) -> Set[str]:
        return {"other vertical", "cable", "mask"}

    def _cloud_classification(
        self, cloud: PointCloud, classification_codes: Mapping[str, int]
    ) -> None:
        if self.projection is None:
            raise ValueError(
                "The input EPSG (`projection`) must be set "
                "before classifying any clouds"
            )
        densify_vegetation(cloud, classification_codes)
        osm_building_classification(cloud, self.projection, classification_codes)
        if np.sum(cloud.classification == classification_codes["rail"]) > 0:
            classify_rail_mask(cloud, classification_codes)
            clean_rail(cloud, classification_codes)
            catenary_all_index = np.where(
                cloud.classification == classification_codes["catenary"]
            )[0]
            classify_vertical_near_rail(cloud, classification_codes)
            cloud.classification[
                cloud.classification == classification_codes["catenary"]
            ] = classification_codes["other vertical"]
            catenary_post_index = classify_catenary_post(cloud, classification_codes)
            cable_index = np.setdiff1d(catenary_all_index, catenary_post_index)
            cloud.classification[cable_index] = classification_codes["cable"]
            classify_cable(cloud, classification_codes)

    def execute_on(
        self, cloud: PointCloud, pipeline_metadata: PipelineMetadata
    ) -> Iterable[PointCloud]:
        if cloud:
            self._cloud_classification(cloud, pipeline_metadata.classification_codes)
        return (cloud,)

    @classmethod
    def options(cls) -> List[Option]:
        return [
            Option(
                "projection",
                "EPSG code of the project the cloud is in",
                type_cast=ProjectTypeEnum,
                required=True,
            )
        ]
